/**
 * Service for SRM problem APIs.
 */
const fs = require('fs');
const path = require('path');
const Joi = require('joi');
const logger = require('../../../common/logger');

let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  const list = Array.isArray(rawTags) ? rawTags : String(rawTags).split(',');
  return list
    .map((tag) => String(tag || '').trim().toLowerCase())
    .filter((tag) => tag);
}

/**
 * Check whether the problem contains at least one of the requested tags.
 * @param {Object} problem
 * @param {Array<string>} tags
 * @returns {boolean}
 */
function problemHasTags(problem, tags) {
  if (!tags || tags.length === 0) {
    return true;
  }
  if (!problem.tags || !Array.isArray(problem.tags)) {
    return false;
  }
  const problemTags = problem.tags.map((t) => t.toLowerCase());
  return tags.some((tag) => problemTags.includes(tag));
}

/**
 * Load problems from data file, cache in memory.
 * @returns {Array<Object>} problems
 */
function loadProblems() {
  if (cachedProblems) {
    return cachedProblems;
  }
  const dataPath = path.resolve(__dirname, '../../../data/problems.json');
  const raw = fs.readFileSync(dataPath, 'utf8');
  cachedProblems = JSON.parse(raw);
  return cachedProblems;
}

/**
 * List problems with optional filters and pagination.
 * @param {Object} query
 * @returns {Promise<Object>} payload with total and results
 */
function* listProblems(query) {
  const problems = loadProblems();

  // Validate and normalize query params
  const schema = Joi.object({
    limit: Joi.number().integer().min(1).max(MAX_LIMIT).default(10),
    offset: Joi.number().integer().min(0).default(0),
    tags: Joi.alternatives().try(Joi.string(), Joi.array().items(Joi.string())).optional()
  });

  const { error, value } = schema.validate(query);
  if (error) {
    throw error;
  }

  const tags = normalizeTags(value.tags);

  // Filter problems by tags
  const filtered = problems.filter((p) => problemHasTags(p, tags));

  // Pagination
  const offset = value.offset;
  const limit = value.limit;
  const paged = filtered.slice(offset, offset + limit);

  return {
    total: filtered.length,
    results: paged
  };
}

